public async Task<bool> PurchaseTicketsAsync(int eventId, int purchaseQuantity)
{
    using (var context = new BookingContext())
    {
        var eventDetails = await context.Events
            .Where(e => e.EventId == eventId)
            .SingleOrDefaultAsync();

        if (eventDetails == null || purchaseQuantity <= 0)
            return false;

        if (eventDetails.AvailableSeats < purchaseQuantity)
            return false;

        bool success = false;
        using (var transaction = await context.Database.BeginTransactionAsync(System.Data.IsolationLevel.Serializable))
        {
            try
            {
                eventDetails.AvailableSeats -= purchaseQuantity;
                context.Events.Update(eventDetails);
                await context.SaveChangesAsync();
                await transaction.CommitAsync();
                success = true;
            }
            catch (Exception)
            {
                await transaction.RollbackAsync();
            }
        }
        return success;
    }
